### MongoDB Schema (Room.js)
```javascript
const mongoose = require('mongoose');

const RoomSchema = new mongoose.Schema({
    roomNumber: { type: String, required: true },
    status: { type: String, enum: ['Available', 'Occupied'], default: 'Available' },
    capacity: { type: Number, required: true },
    type: { type: String, required: true }
});

module.exports = mongoose.model('Room', RoomSchema);
```

### Express Route (roomRoutes.js)
```javascript
const express = require('express');
const Room = require('../models/Room');
const router = express.Router();

// Get all rooms
router.get('/', async (req, res) => {
    try {
        const rooms = await Room.find();
        res.json(rooms);
    } catch (err) {
        res.status(500).json({ message: err.message });
    }
});

// Add a new room
router.post('/', async (req, res) => {
    const room = new Room({
        roomNumber: req.body.roomNumber,
        status: req.body.status,
        capacity: req.body.capacity,
        type: req.body.type
    });

    try {
        const newRoom = await room.save();
        res.status(201).json(newRoom);
    } catch (err) {
        res.status(400).json({ message: err.message });
    }
});

module.exports = router;
```

### React Component (RoomList.js)
```jsx
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function RoomList() {
    const [rooms, setRooms] = useState([]);

    useEffect(() => {
        fetchRooms();
    }, []);

    const fetchRooms = async () => {
        const response = await axios.get('/api/rooms');
        setRooms(response.data);
    };

    return (
        <div>
            <h1>Room List</h1>
            <ul>
                {rooms.map(room => (
                    <li key={room._id}>{room.roomNumber} - {room.status}</li>
                ))}
            </ul>
        </div>
    );
}

export default RoomList;
```

### Summary
- **MongoDB** stores room data.
- **Express** handles CRUD operations.
- **React** fetches and displays room data.

